from agent import *from models.products import *def strip_namespace(data):    tmp = data.content_file + ".tmp"    out = file(tmp, "w")    for line in file(data.content_file):        line = line.replace('<ns0', '<')        line = line.replace('ns0:', '')        line = line.replace(' xmlns', ' abcde=')        out.write(line + "\n")    out.close()    os.rename(tmp, data.content_file)def run(context, session):    session.sessionbreakers = [SessionBreak(max_requests=6000)]    session.queue(Request('https://hrej.cz/reviews'), process_revlist, dict())def process_revlist(data, context, session):    strip_namespace(data)    revs = data.xpath('//h2[@class="un-card-headline"]//a')    for rev in revs:        title = rev.xpath('text()').string()        url = rev.xpath('@href').string()        session.queue(Request(url), process_review, dict(title=title, url=url))    next_url = data.xpath('//link[@rel="next"]/@href').string()    if next_url:        session.queue(Request(next_url), process_revlist, dict(context))def process_review(data, context, session):    strip_namespace(data)    product = Product()    product.category = "Games"    product.url = data.xpath('//li[regexp:test(., "Doporučená cena", "i")]//a[contains(@rel, "sponsored")]/@href').string() or context['url']    manufacturer = data.xpath('''//script[contains(., '"creator":')]/text()''').string()    if manufacturer:        product.manufacturer = manufacturer.split('"creator":{')[-1].split('}', 1)[0].split('"name":')[-1].strip('" ')    review = Review()    review.title = context['title']    review.type = "pro"    review.url = context['url']    date = data.xpath('//div[contains(@class, "info_")]//time/@datetime').string()    if date:        review.date = date.split(' ')[0]    authors = data.xpath('//p[@class="post-header-info__name"]/a')    for author in authors:        author_name = author.xpath('text()').string()        author_url = author.xpath('@href').string()        if author_name and author_url:            author_ssid = author_url.strip('/').split('/')[-1]            review.authors.append(Person(name=author_name, profile_url=author_url, ssid=author_ssid))    context['excerpt'] = data.xpath('//p[preceding::div[@class="post-body"] and (following::section[@class="review-box"] or following::div[contains(@class, "post-chapters--footer")]) and not(ancestor::div[@class="post-body__perex"])]//text()').string(multiple=True)    context['product'] = product    next_page = data.xpath('//a[span[text()="Další" or text()="Poslední"] and not(@disabled="disabled")]/@href').string()    if next_page:        title = data.xpath('//a[contains(@class, "post-chapters__item--active")]/text()').string()        if title:            title = title.split('1.')[-1].strip()            review.add_property(type='pages', value=dict(title=title, url=context['url']))        else:            review.add_property(type='pages', value=dict(title=review.title+' - page 1', url=data.response_url))        session.do(Request(next_page), process_review_next, dict(context, review=review, page=2))    else:        context['page'] = 1        context['review'] = review        process_review_next(data, context, session)def process_review_next(data, context, session):    strip_namespace(data)    product = context['product']    review = context['review']    excerpt = context['excerpt']    page = context['page']    if page > 1:        title = data.xpath('//a[contains(@class, "post-chapters__item--active")]/text()').string()        if title:            title = title.split(str(page) + '.')[-1].strip()            review.add_property(type='pages', value=dict(title=title, url=data.response_url))        else:            review.add_property(type='pages', value=dict(title=review.title+' - page '+str(page), url=data.response_url))        excerpt_next = data.xpath('//p[preceding::div[@class="post-body"] and (following::section[@class="review-box"] or following::div[contains(@class, "post-chapters--footer")]) and not(ancestor::div[@class="post-body__perex"])]//text()').string(multiple=True)        if excerpt_next:            excerpt = excerpt.strip() + ' ' + excerpt_next.strip()    product.name = data.xpath('//a[contains(@class, "review-box__title")]/text()').string() or data.xpath('//h1[@class="post-header__title"]//span[not(@class)]/text()').string()    product.ssid = data.xpath('//div/@data-commentable-id').string()    platforms = data.xpath('//span[@class="un-chip__text"][not(ancestor::*[self::a or self::button])][not(regexp:test(., "Hrej.cz", "i"))]/text()').strings()    for platform in platforms:        product.category += '|' + platform.replace('|', '\\')    review.ssid = product.ssid    grade_overall = data.xpath('//div/@data-rating').string()    if grade_overall:        review.grades.append(Grade(type="overall", value=float(grade_overall)/10, best=10.0))    pros = data.xpath('//div[contains(@class, "proscons-pros")]//span[contains(@class, "text")]//text()').strings()    for pro in pros:        review.add_property(type="pros", value=pro.strip())    cons = data.xpath('//div[contains(@class, "proscons-cons")]//span[contains(@class, "text")]//text()').strings()    for con in cons:        review.add_property(type="cons", value=con.strip())    if not context.get('summary'):        context['summary'] = data.xpath('//div[contains(@class, "perex")]/p//text()').string(multiple=True)    conclusion = data.xpath('//div[contains(@class, "verdict")]/p//text()').string(multiple=True)    if not conclusion:        conclusion = data.xpath('//p[preceding::h2[regexp:test(., "ZÁVĚR", "i")] and (following::section[@class="review-box"] or following::div[contains(@class, "post-chapters--footer")])]//text()').string(multiple=True)    next_page = data.xpath('//a[span[text()="Další" or text()="Poslední"] and not(@disabled="disabled")]/@href').string()    if next_page:        session.do(Request(next_page), process_review_next, dict(context, page=page+1, product=product, review=review))    elif excerpt:        if context['summary']:            review.add_property(type="summary", value=context['summary'])        if conclusion:            review.add_property(type="conclusion", value=conclusion)            excerpt = excerpt.replace(conclusion.strip(), '').strip()        review.add_property(type="excerpt", value=excerpt)        product.reviews.append(review)        session.emit(product)